function PostCard({ post }) {
  return (
    <div className="post-card">
      <h2>{post.title}</h2>

      <p>{post.content}</p>

      <div className="author">
        Author: {post.author?.username || "Unknown"}
      </div>
    </div>
  );
}

export default PostCard;
